import{_ as t,o as a,c as r,ag as o}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"Correlations","description":"","frontmatter":{},"headers":[],"relativePath":"guide/correlations.md","filePath":"guide/correlations.md","lastUpdated":1772287587000}'),i={name:"guide/correlations.md"};function s(n,e,l,d,h,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="correlations" tabindex="-1">Correlations <a class="header-anchor" href="#correlations" aria-label="Permalink to &quot;Correlations&quot;">​</a></h1><p>The Correlations view plots two biomarkers against each other as a scatter chart. Each point represents a single lab date, positioned by the values of both markers on that date. This reveals whether the two markers tend to rise and fall together — or move in opposite directions.</p><h2 id="opening-the-correlations-view" tabindex="-1">Opening the Correlations View <a class="header-anchor" href="#opening-the-correlations-view" aria-label="Permalink to &quot;Opening the Correlations View&quot;">​</a></h2><p>Select <strong>Correlations</strong> in the sidebar. You will see two marker selectors — one for the horizontal (X) axis and one for the vertical (Y) axis. Choose any two markers from your data and the scatter plot updates immediately.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You need at least three lab entries to see a meaningful scatter pattern. More dates produce a more informative plot.</p></div><h2 id="how-values-are-normalized" tabindex="-1">How Values Are Normalized <a class="header-anchor" href="#how-values-are-normalized" aria-label="Permalink to &quot;How Values Are Normalized&quot;">​</a></h2><p>Values on both axes are shown as a <strong>percentage of the reference range</strong>, where 0% is the lower reference limit and 100% is the upper limit. Normalizing this way means you can compare markers with very different units or scales on the same chart — a glucose value in mmol/L and a ferritin value in µg/L land on the same 0–100% grid.</p><p>Values outside the reference range appear below 0% or above 100%, making it easy to see when both markers were simultaneously out of range.</p><h2 id="preset-correlation-pairs" tabindex="-1">Preset Correlation Pairs <a class="header-anchor" href="#preset-correlation-pairs" aria-label="Permalink to &quot;Preset Correlation Pairs&quot;">​</a></h2><p>getbased includes a set of curated preset pairs for commonly studied relationships — for example, LDL and triglycerides, or glucose and insulin. Select a preset from the dropdown to jump directly to that pair without manually choosing both markers.</p><h2 id="interpreting-results" tabindex="-1">Interpreting Results <a class="header-anchor" href="#interpreting-results" aria-label="Permalink to &quot;Interpreting Results&quot;">​</a></h2><p>A cluster of points running from lower-left to upper-right suggests the two markers tend to rise together (positive correlation). A cluster running from upper-left to lower-right suggests they move in opposite directions (negative correlation). A scattered cloud with no clear direction suggests the markers are not strongly related in your data.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Correlation in your personal data does not prove causation, and a small number of data points can produce misleading patterns. Use correlations as a starting point for conversations with your healthcare provider, not as a definitive finding.</p></div><h2 id="date-range-filter" tabindex="-1">Date Range Filter <a class="header-anchor" href="#date-range-filter" aria-label="Permalink to &quot;Date Range Filter&quot;">​</a></h2><p>The active date range filter applies to the correlations view. Only lab dates within the selected range appear as points on the scatter plot. Narrowing the range lets you examine whether a relationship between two markers changed during a specific period.</p>',15)])])}const m=t(i,[["render",s]]);export{u as __pageData,m as default};
